import type { CatalogUiField, CatalogUiSchema } from '../../types/catalogUiSchema';
import { isErpListUiSchemaKind, LIST_UI_SCHEMA_KIND } from '../../types/catalogUiSchema';

/** Design SSOT — khớp cột list / DTO; bổ sung key mới từ sample row tự động. */
const FIELD_BLUEPRINT: Record<string, Array<{ key: string; label: string; format?: string | null }>> = {
  [LIST_UI_SCHEMA_KIND.cashReceipt]: [
    { key: 'code', label: 'Số phiếu', format: null },
    { key: 'voucherDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'customerName', label: 'Đối tác' },
    { key: 'description', label: 'Diễn giải' },
    { key: 'amount', label: 'Số tiền', format: 'vnd' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
  [LIST_UI_SCHEMA_KIND.cashPayment]: [
    { key: 'code', label: 'Số phiếu', format: null },
    { key: 'voucherDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'customerName', label: 'Đối tác' },
    { key: 'description', label: 'Diễn giải' },
    { key: 'amount', label: 'Số tiền', format: 'vnd' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
  [LIST_UI_SCHEMA_KIND.journalEntry]: [
    { key: 'code', label: 'Số CT' },
    { key: 'entryDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'description', label: 'Diễn giải' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
  [LIST_UI_SCHEMA_KIND.purchaseInvoice]: [
    { key: 'code', label: 'Số HĐ' },
    { key: 'invoiceDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'supplierName', label: 'NCC' },
    { key: 'totalAmount', label: 'Tổng tiền', format: 'vnd' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
  [LIST_UI_SCHEMA_KIND.advancePayment]: [
    { key: 'code', label: 'Số phiếu', format: null },
    { key: 'voucherDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'customerName', label: 'Người tạm ứng' },
    { key: 'description', label: 'Diễn giải' },
    { key: 'amount', label: 'Số tiền', format: 'vnd' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
  [LIST_UI_SCHEMA_KIND.bankInternalTransfer]: [
    { key: 'code', label: 'Số chứng từ', format: null },
    { key: 'voucherDate', label: 'Ngày', format: 'voucherDate' },
    { key: 'transferReasonCode', label: 'Lý do chuyển' },
    { key: 'fromPaymentChannelCode', label: 'Kênh đi' },
    { key: 'toPaymentChannelCode', label: 'Kênh đến' },
    { key: 'amount', label: 'Số tiền', format: 'vnd' },
    { key: 'processingLevel', label: 'Mức xử lý', format: 'processingLevel' },
  ],
};

const SKIP_ROW_KEYS = new Set(['id', 'lines', 'createdAt', 'updatedAt', 'companyCode']);

function labelFromKey(key: string): string {
  if (key === 'customerName') return 'Đối tác';
  if (key === 'supplierName') return 'NCC';
  if (key === 'voucherDate' || key === 'entryDate' || key === 'invoiceDate') return 'Ngày';
  if (key === 'processingLevel') return 'Mức xử lý';
  if (key === 'description') return 'Diễn giải';
  if (key === 'amount' || key === 'totalAmount') return 'Số tiền';
  if (key === 'code') return 'Mã';
  return key;
}

function mergeBlueprintWithRow(
  catalogKind: string,
  sampleRow?: Record<string, unknown> | null,
): Array<{ key: string; label: string; format?: string | null }> {
  const base = [...(FIELD_BLUEPRINT[catalogKind] ?? [])];
  const seen = new Set(base.map(b => b.key));
  if (sampleRow) {
    for (const key of Object.keys(sampleRow)) {
      if (SKIP_ROW_KEYS.has(key) || seen.has(key)) continue;
      if (key === 'status') continue;
      seen.add(key);
      base.push({ key, label: labelFromKey(key) });
    }
  }
  return base;
}

export function buildBootstrapFields(
  catalogKind: string,
  sampleRow?: Record<string, unknown> | null,
  serverFields?: CatalogUiField[] | null,
): CatalogUiField[] {
  if (serverFields?.length) {
    return serverFields.map(f => ({
      ...f,
      list: f.list ?? { visible: true, order: 0 },
    }));
  }

  const merged = mergeBlueprintWithRow(catalogKind, sampleRow);
  return merged.map((b, i) => ({
    key: b.key,
    control: b.format === 'vnd' ? 'MONEY' : b.key === 'code' ? 'CODE' : 'TEXT',
    label: b.label,
    format: b.format ?? null,
    list: {
      visible: b.key !== 'status',
      order: (i + 1) * 10,
      width: b.format === 'vnd' ? '9rem' : undefined,
      variant: b.key === 'code' ? 'badge' : undefined,
    },
    lookup: { visible: false, order: 0 },
    form: { visible: false },
    proposal: { editable: false, order: 0 },
    configurable: b.key !== 'status' && b.key !== 'id',
    systemOnly: b.key === 'status',
  }));
}

/** Schema draft khi chưa có tenant override hoặc GET lỗi — Lưu = PUT insert override. */
export function buildBootstrapSchema(
  catalogKind: string,
  sampleRow?: Record<string, unknown> | null,
  serverSchema?: CatalogUiSchema | null,
): CatalogUiSchema {
  const fields = buildBootstrapFields(
    catalogKind,
    sampleRow,
    serverSchema?.fields,
  );
  const searchKeys = fields
    .filter(f => f.list?.visible && f.key !== 'status')
    .slice(0, 4)
    .map(f => f.key);

  return {
    catalogKind,
    schemaVersion: serverSchema?.schemaVersion ?? 1,
    configMode: true,
    fields,
    lookup: serverSchema?.lookup ?? {
      searchFieldKeys: searchKeys.length ? searchKeys : ['code'],
      primaryDisplayKey: searchKeys[0] ?? 'code',
      secondaryDisplayKey: searchKeys[1] ?? null,
    },
    list: serverSchema?.list ?? {
      searchFieldKeys: searchKeys,
      defaultPageSize: 20,
      stickyHeader: true,
      heightMode: 'auto',
      resizableColumns: true,
    },
    hintText: serverSchema?.hintText ?? null,
    tableConfig: serverSchema?.tableConfig ?? null,
  };
}

export function resolveListDisplaySchema(
  catalogKind: string,
  serverSchema: CatalogUiSchema | null,
  sampleRow?: Record<string, unknown> | null,
  loadFailed?: boolean,
): { schema: CatalogUiSchema | null; isBootstrap: boolean } {
  if (serverSchema?.fields?.length && !loadFailed) {
    const hasVisible = serverSchema.fields.some(f => f.list?.visible);
    if (hasVisible) {
      return { schema: serverSchema, isBootstrap: false };
    }
  }
  if (!isErpListUiSchemaKind(catalogKind) && !serverSchema && !sampleRow) {
    return { schema: null, isBootstrap: false };
  }
  return {
    schema: buildBootstrapSchema(catalogKind, sampleRow, serverSchema),
    isBootstrap: true,
  };
}
