import React from 'react';
import type { CatalogUiField } from '../../types/catalogUiSchema';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import erp from '../../styles/erpPage.module.css';

export interface ListSchemaCellProps {
  field: CatalogUiField;
  row: Record<string, unknown>;
  testIdPrefix: string;
  formatProcessingLevel?: (level: string) => string;
}

export const ListSchemaCell: React.FC<ListSchemaCellProps> = ({
  field,
  row,
  testIdPrefix,
  formatProcessingLevel,
}) => {
  const value = row[field.key];
  const codeStr = value == null ? '' : String(value);

  if (field.format === 'voucherDate' || field.key === 'voucherDate' || field.key === 'entryDate' || field.key === 'invoiceDate') {
    return (
      <td>{value ? formatDateLocal(String(value)) : '—'}</td>
    );
  }

  if (field.format === 'vnd' || field.key === 'amount' || field.key === 'totalAmount') {
    const num = typeof value === 'number' ? value : Number(value);
    return (
      <td className={erp.colAmount}>
        {Number.isFinite(num) ? formatVnd(num) : '—'}
      </td>
    );
  }

  if (field.format === 'processingLevel' || field.key === 'processingLevel') {
    const level = value == null ? '' : String(value);
    return (
      <td data-testid={`${testIdPrefix}-row-${row.id}-processing-level`}>
        {formatProcessingLevel ? formatProcessingLevel(level) : level || '—'}
      </td>
    );
  }

  if (field.control === 'CODE' || field.key === 'code') {
    return (
      <td>
        <code>{codeStr}</code>
      </td>
    );
  }

  return <td>{value == null || value === '' ? '—' : String(value)}</td>;
};
