import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import {
  getErpListToolbarActionIcon,
  getErpListToolbarActionLabel,
} from '@linm-soft-org/linm-web-common-components';
import styles from './VoucherRowActionMenu.module.css';

export type VoucherRowMenuAction = 'view' | 'edit' | 'viewLedger' | 'print';

export type VoucherRowActionMenuProps = {
  open: boolean;
  x: number;
  y: number;
  onClose: () => void;
  onSelect: (action: VoucherRowMenuAction) => void;
  testIdPrefix: string;
  showView?: boolean;
  showEdit?: boolean;
  showViewLedger?: boolean;
  showPrint?: boolean;
  viewLedgerDisabled?: boolean;
  printDisabled?: boolean;
};

export const VoucherRowActionMenu: React.FC<VoucherRowActionMenuProps> = ({
  open,
  x,
  y,
  onClose,
  onSelect,
  testIdPrefix,
  showView = true,
  showEdit = false,
  showViewLedger = true,
  showPrint = true,
  viewLedgerDisabled = false,
  printDisabled = false,
}) => {
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  const clampedY = Math.min(y, window.innerHeight - 220);
  const clampedX = Math.min(x, window.innerWidth - 220);

  const pick = (action: VoucherRowMenuAction) => {
    onSelect(action);
    onClose();
  };

  const hasPrimary = showView || showEdit;
  const hasOverflow = showViewLedger || showPrint;

  return createPortal(
    <>
      <div
        role="presentation"
        style={{ position: 'fixed', inset: 0, zIndex: 1299 }}
        onMouseDown={onClose}
        data-testid={`${testIdPrefix}-row-menu-backdrop`}
      />
      <div
        className={styles.menu}
        style={{ left: clampedX, top: clampedY }}
        role="menu"
        data-testid={`${testIdPrefix}-row-menu`}
      >
        {showView ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('view')}
            data-testid={`${testIdPrefix}-row-menu-view`}
          >
            <i className={getErpListToolbarActionIcon('view')} aria-hidden />
            {getErpListToolbarActionLabel('view')}
          </button>
        ) : null}
        {showEdit ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('edit')}
            data-testid={`${testIdPrefix}-row-menu-edit`}
          >
            <i className={getErpListToolbarActionIcon('edit')} aria-hidden />
            {getErpListToolbarActionLabel('edit')}
          </button>
        ) : null}
        {hasPrimary && hasOverflow ? <div className={styles.separator} /> : null}
        {showViewLedger ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            disabled={viewLedgerDisabled}
            onClick={() => !viewLedgerDisabled && pick('viewLedger')}
            data-testid={`${testIdPrefix}-row-menu-view-ledger`}
          >
            <i className={getErpListToolbarActionIcon('viewLedger')} aria-hidden />
            {getErpListToolbarActionLabel('viewLedger')}
          </button>
        ) : null}
        {showPrint ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            disabled={printDisabled}
            onClick={() => !printDisabled && pick('print')}
            data-testid={`${testIdPrefix}-row-menu-print`}
          >
            <i className={getErpListToolbarActionIcon('print')} aria-hidden />
            {getErpListToolbarActionLabel('print')}
          </button>
        ) : null}
      </div>
    </>,
    document.body,
  );
};
